from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Optional
import asyncio

app = FastAPI(title='Task Manager API')

class TaskCreate(BaseModel):
    title: str
    priority: int = 1
    completed: bool = False

class TaskResponse(TaskCreate):
    id: int

tasks_db: dict[int, TaskCreate] = {}
counter = 0

@app.post('/tasks', response_model=TaskResponse, status_code=201)
async def create_task(task: TaskCreate):
    global counter
    counter += 1
    tasks_db[counter] = task
    return TaskResponse(id=counter, **task.model_dump())

@app.get('/tasks/{task_id}', response_model=TaskResponse)
async def get_task(task_id: int):
    if task_id not in tasks_db:
        raise HTTPException(status_code=404, detail='Task not found')
    return TaskResponse(id=task_id, **tasks_db[task_id].model_dump())

@app.get('/tasks')
async def list_tasks(completed: Optional[bool] = None):
    results = [{'id': k, **v.model_dump()} for k, v in tasks_db.items()]
    if completed is not None:
        results = [t for t in results if t['completed'] == completed]
    return results
